import { inject, Injectable } from '@angular/core';
import { AXCalendarService } from '@acorex/core/date-time';

@Injectable({ providedIn: 'root' })
export class DateTimeBasicDemo {
  private calendar = inject(AXCalendarService);

  demo() {
    // Current moment in the active calendar
    const today = this.calendar.now();

    // Create from calendar parts
    const birthDate = this.calendar.create(
      { year: 1370, month: 1, day: 15 },
      'solar-hijri',
    );

    // Create from ISO string or native Date
    const fromIso = this.calendar.create('2025-06-10T12:30:00');

    // Date arithmetic — returns a new AXDateTime instance
    const nextWeek = today.add('day', 7);
    const monthStart = today.startOf('month');

    // Format for display
    const label = today.format('yyyy/MM/dd HH:mm');
    const shortLabel = this.calendar.format(today, 'shortDate', {
      calendar: 'solar-hijri',
    });

    // Switch active calendar at runtime
    this.calendar.setActiveCalendar('solar-hijri');

    return { today, birthDate, fromIso, nextWeek, monthStart, label, shortLabel };
  }
}

import { ApplicationConfig, importProvidersFrom } from '@angular/core';
import { AXDateTimeModule } from '@acorex/core/date-time';
import { AXFormatModule } from '@acorex/core/format';

export const appConfig: ApplicationConfig = {
  providers: [
    // Registers date, datetime, time, timeleft, time-duration formatters
    importProvidersFrom(AXDateTimeModule, AXFormatModule.forRoot()),
  ],
};

import { inject } from '@angular/core';
import { AXCalendarService } from '@acorex/core/date-time';

export class DateDemo {
  private calendar = inject(AXCalendarService);

  examples() {
    // Current moment in active calendar
    const now = this.calendar.now();

    // From native Date or ISO string
    const fromDate = this.calendar.create(new Date());
    const fromIso = this.calendar.create('2025-06-10T12:30:00');

    // From calendar parts (Gregorian)
    const gregorian = this.calendar.create(
      { year: 2025, month: 6, day: 10, hours: 14, minutes: 30 },
      'gregorian',
    );

    // From Solar Hijri parts
    const persian = this.calendar.create(
      { year: 1404, month: 3, day: 20 },
      'solar-hijri',
    );

    // Validation
    this.calendar.isValidDate({ year: 1404, month: 3, day: 20 }); // true
    this.calendar.isValidDate('not-a-date'); // false

    return { now, fromDate, fromIso, gregorian, persian };
  }
}

import { Component, inject, OnInit } from '@angular/core';
import { AXCalendarService } from '@acorex/core/date-time';

@Component({
  selector: 'app-calendar-toggle',
  template: `
    <button (click)="useGregorian()">Gregorian</button>
    <button (click)="usePersian()">Solar Hijri</button>
    <p>Active: {{ activeCalendar }}</p>
    <p>Today: {{ todayFormatted }}</p>
  `,
})
export class CalendarToggleComponent implements OnInit {
  private calendarService = inject(AXCalendarService);

  activeCalendar = this.calendarService.calendar.name();
  todayFormatted = '';

  ngOnInit() {
    this.refresh();

    this.calendarService.calendarChanges$.subscribe((cal) => {
      this.activeCalendar = cal.name();
      this.refresh();
    });
  }

  useGregorian() {
    this.calendarService.setActiveCalendar('gregorian');
  }

  usePersian() {
    this.calendarService.setActiveCalendar('solar-hijri');
  }

  private refresh() {
    const today = this.calendarService.now();
    this.todayFormatted = today.format('yyyy/MM/dd');
  }
}

import { inject } from '@angular/core';
import { AXCalendarService, AXDateTimeRange } from '@acorex/core/date-time';

export class DateMathDemo {
  private calendar = inject(AXCalendarService);

  demo() {
    const start = this.calendar.now('solar-hijri');

    // Add / subtract
    const nextWeek = start.add('day', 7);
    const prevMonth = start.add('month', -1);

    // Start / end of unit
    const monthStart = start.startOf('month');
    const monthEnd = start.endOf('month');

    // Comparison
    const isPast = start.isBefore(nextWeek, 'day');
    const sameMonth = start.isSame(prevMonth, 'month');

    // Duration between two dates
    const span = start.duration(nextWeek);
    console.log(span.days, span.hours);

    // Enumerate days in a range
    const range = new AXDateTimeRange(monthStart, monthEnd);
    const daysInMonth = range.enumerate('day');

    return { nextWeek, monthStart, monthEnd, isPast, sameMonth, daysInMonth };
  }
}

import { Component, inject } from '@angular/core';
import { AXCalendarService, AXDateTimeFormatter } from '@acorex/core/date-time';
import { AXFormatPipe } from '@acorex/core/format';
import { AsyncPipe } from '@angular/common';

@Component({
  selector: 'app-formatted-date',
  imports: [AXFormatPipe, AsyncPipe],
  template: `
    <!-- Recommended: format pipe -->
    <p>{{ today | format: 'date' : { format: 'long', calendar: 'solar-hijri' } | async }}</p>
    <p>{{ today | format: 'datetime' : { format: 'short' } | async }}</p>
    <p>{{ today | format: 'time' : { format: 'HH:mm' } | async }}</p>

    <!-- Custom pattern via service -->
    <p>{{ customFormatted }}</p>
  `,
})
export class FormattedDateComponent {
  private calendar = inject(AXCalendarService);
  private datetimeFormatter = inject(AXDateTimeFormatter);

  today = this.calendar.now();

  customFormatted = this.calendar.format(this.today, 'yyyy/MM/dd HH:mm', {
    calendar: 'solar-hijri',
  });

  // Or via formatter directly
  longPersian = this.datetimeFormatter.format(this.today, {
    format: 'full',
    calendar: 'solar-hijri',
    locale: 'fa-IR',
  });
}

import { inject } from '@angular/core';
import { AXCalendarService } from '@acorex/core/date-time';

export class FormatTokensDemo {
  private calendar = inject(AXCalendarService);

  demo() {
    const dt = this.calendar.now('solar-hijri');

    return {
      date: dt.format('yyyy/MM/dd'),       // 1404/03/20
      time24: dt.format('HH:mm:ss'),       // 14:30:00
      weekday: dt.format('dddd'),          // localized weekday name
      monthName: dt.format('MMMM'),        // localized month name
      preset: dt.format('shortDate'),      // locale short date
      datetime: dt.format('yyyy/MM/dd HH:mm'),
    };
  }
}

import { inject } from '@angular/core';
import {
  AXTimeDurationFormatter,
  AXTimeLeftFormatter,
} from '@acorex/core/date-time';

export class DurationDemo {
  private durationFormatter = inject(AXTimeDurationFormatter);
  private timeLeftFormatter = inject(AXTimeLeftFormatter);

  demo() {
    // Duration from milliseconds
    const elapsed = this.durationFormatter.format(125_000, { format: 'HH:mm:ss' });

    // Relative time (auto unit: now, minutes, hours, days...)
    const deadline = new Date(Date.now() + 5 * 60 * 1000);
    const remaining = this.timeLeftFormatter.format(deadline);

    // Past event
    const past = this.timeLeftFormatter.format(
      new Date(Date.now() - 3 * 60 * 60 * 1000),
      { format: 'h' },
    );

    return { elapsed, remaining, past };
  }

  async breakdown() {
    // Full unit breakdown with labels
    return this.durationFormatter.millisecondsToMask(
      9_876_543_210,
      'DAY',
      'SECOND',
      true,
    );
  }
}

import { AXSolarHijriCalendar } from '@acorex/core/date-time';

const calendar = new AXSolarHijriCalendar({
  weekdays: [6, 0, 1, 2, 3, 4, 5],
  weekend: [6],
});

// Create a Jalali date
const dt = calendar.create({ year: 1403, month: 10, day: 1, hours: 12 });

// Convert between systems
const gregorianDate = calendar.toGregorian(1403, 10, 1);
const jalaliParts = calendar.toSolarHijri(new Date());

// Calendar math
const nextMonth = calendar.add(new Date(), 'month', 1);
const startOfYear = calendar.startOf(new Date(), 'year');

// Validation
const isValid = calendar.isValidSolarHijriDate(1403, 10, 1);
const isLeap = calendar.isLeapSolarHijriYear(1403);

console.log({ dt, gregorianDate, jalaliParts, nextMonth, isValid, isLeap });

import { AXGregorianCalendar } from '@acorex/core/date-time';

const calendar = new AXGregorianCalendar({
  weekdays: [0, 1, 2, 3, 4, 5, 6],
  weekend: [5, 6],
});

const dt = calendar.create({ year: 2025, month: 6, day: 10 });

const year = calendar.year(dt.date);           // 2025
const month = calendar.monthOfYear(dt.date);   // 6
const day = calendar.dayOfMonth(dt.date);      // 10

const endOfMonth = calendar.endOf(dt.date, 'month');
const inTwoWeeks = calendar.add(dt.date, 'week', 2);

console.log({ year, month, day, endOfMonth, inTwoWeeks });

import { Component, inject, OnInit } from '@angular/core';
import {
  AXCalendarService,
  AX_DATETIME_HOLIDAYS_LOADER,
  AXHolidayDate,
  AXHolidaysLoader,
} from '@acorex/core/date-time';

// Custom loader implementation
class MyHolidaysLoader implements AXHolidaysLoader {
  getHolidays() {
    return Promise.resolve<AXHolidayDate[]>([
      { date: new Date(2025, 2, 20), title: 'Nowruz', cssClass: 'holiday' },
    ]);
  }
}

// Register in app config:
// { provide: AX_DATETIME_HOLIDAYS_LOADER, useClass: MyHolidaysLoader }

@Component({ selector: 'app-holiday-list', template: `@for (h of holidays; track h.title) { <li>{{ h.title }}</li> }` })
export class HolidayListComponent implements OnInit {
  private calendarService = inject(AXCalendarService);
  holidays: AXHolidayDate[] = [];

  ngOnInit() {
    this.calendarService.onHolidaysChanged.subscribe((list) => {
      this.holidays = list;
    });

    this.calendarService.loadHolidays({ calendar: 'solar-hijri' });
  }
}
